import {
    themeQuartz,
    themeBalham,
    themeMaterial,
    themeAlpine,
    Theme,
    colorSchemeLightWarm,
    colorSchemeLightCold,
    colorSchemeDarkWarm,
    colorSchemeDarkBlue,
  } from 'ag-grid-enterprise';

  // Custom Pink Theme
  const themePink: Theme = themeQuartz.withParams({
    backgroundColor: "rgb(249, 245, 227)",
    foregroundColor: "rgb(126, 46, 132)",
    headerTextColor:  "rgb(204, 245, 172)",
    headerBackgroundColor: "rgb(209, 64, 129)",
    oddRowBackgroundColor: "rgba(0, 0, 0, 0.03)",
    headerColumnResizeHandleColor: "rgb(126, 46, 132)",
    selectedRowBackgroundColor: "rgba(0, 255, 0, 0.1)"
  });

  // Export all themes in one place
  export const GRID_THEME_CONFIG: Record<string, Theme> = {
    // Default themes
    quartz: themeQuartz,
    balham: themeBalham,
    material: themeMaterial,
    alpine: themeAlpine,

    // Custom
    custom: themePink,

    // Color schemes
    quartzLightWarm: themeQuartz.withPart(colorSchemeLightWarm),
    quartzLightCold: themeQuartz.withPart(colorSchemeLightCold),
    quartzDarkWarm: themeQuartz.withPart(colorSchemeDarkWarm),
    quartzDarkBlue: themeQuartz.withPart(colorSchemeDarkBlue),
  };

export const RFQ_COLUMN_HEADERS_CONFIG: any = {
    columnDefs: getColumnDefs()
};

// Column order in getColumnDefs() drives RFQ grid UI order (via colHeaders + buildRfqColumnStateInConfigOrder).

function getColumnDefs() {
    const commonDefaults = {
        filter: "agMultiColumnFilter",
        cellRenderer: null,
        hide: false,
        rowDrag: false,
        rowGroup: false,
        headerName: null,
        editable: true,
        cellEditor: null,
        headerStyle: {}
    };

    const headerIcon = (icon: string) =>
        `<i class="${icon}" style="font-size:medium; opacity:0.75; color: #ff4081;"></i>`;

    const SORT_ICONS = {
        sortAscending: headerIcon("fa fa-sort-alpha-up"),
        sortDescending: headerIcon("fa fa-sort-alpha-down"),
      };

      const withSortIcons = () => ({
        ...SORT_ICONS
      });

    const addColumn = (
        field: string,
        colId: string,
        width: number,
        overrides: any = {}
    ) => {
        const { roles, ...rest } = overrides;
        return {
            field,
            colId,
            width,
            ...commonDefaults,
            icons: withSortIcons(),
            ...rest,
            ...(roles !== undefined ? { context: { roles } } : {})
        };
    };

    const columns = [
        addColumn("Price Code", "price_code", 200, {
            filter: "agMultiColumnFilter",
            cellRenderer: "agGroupCellRenderer",
            editable: false,
            pinned: "left",
            roles: ['admin', 'sourcing_manager', 'sales', 'designer', 'production', 'vendor']
        }),
        addColumn("Picture", "pic", 130, { filter: false, sortable: false, editable: true, roles: ['admin', 'sourcing_manager', 'sales', 'designer', 'production', 'vendor'] }),
        addColumn("Description", "desc", 448, { roles: ['admin', 'sourcing_manager', 'sales', 'designer', 'production', 'vendor'] }),
        addColumn("RFQ Group", "rfq_group", 194, {rowGroup: true, cellEditor: "autoCompelete", sortable: true, enableRowGroup: true, roles: ['admin', 'sourcing_manager', 'sales', 'designer', 'production', 'vendor'] }),
        addColumn("Item Label", "item_label", 130, { hide: true, roles: ['admin', 'sourcing_manager', 'sales', 'designer', 'production'] }),
        addColumn("Date Modified", "date_mod", 225, {
            filter: "agDateColumnFilter",
            editable: false,
            cellEditor: "datePicker",
            valueFormatter: "dateFormatter",
            comparator: "dateComparator",
            sortable: true,
            roles: ['admin', 'sourcing_manager', 'sales', 'designer', 'production', 'vendor']
        }),
        addColumn("Step", "step", 130, {
            filter: "agSetColumnFilter",
            cellEditor: "autoCompelete",
            cellRenderer: "stepIndicatorRenderer",
            filterParams: {
                comparator: (a: string, b: string) => {
                    const order: { [key: string]: number } = {
                        '@sales for details': 1,
                        '@sourcing': 2,
                        '@factories': 3,
                        'px sent to sales': 4,
                        'px sent to cust': 5,
                        null: 6,  // Blanks
                        'For Later': 7
                    };
                    return order[a] - order[b];
                }
            },
            roles: ['admin', 'sourcing_manager', 'sales', 'designer', 'production'] 
        }),
        addColumn("Date Sent To Factory", "factory_updated", 200, {
            field: "Factory_updated",
            headerName: "Date Sent To Factory",
            editable: false,
            sortable: true,
            filter: "agDateColumnFilter",
            roles: ['admin', 'sourcing_manager', 'sales', 'designer', 'production']
        }),
        addColumn("Group", "group", 119, { roles: ['admin', 'sales'] }),
        addColumn("Material", "material", 200, { roles: ['admin', 'sourcing_manager', 'sales', 'designer', 'production', 'vendor'] }),
        addColumn("Construction", "construction", 225, { roles: ['admin', 'sourcing_manager', 'sales', 'designer', 'production', 'vendor'] }),
		addColumn("Treatment", "treatment", 250, { roles: ['admin', 'sourcing_manager', 'sales', 'designer', 'production', 'vendor'] }),
        addColumn("Tech Pack Link", "tech_pack_url", 240, { roles: ['admin', 'sourcing_manager', 'sales', 'designer', 'production', 'vendor'] }),
        addColumn("Size (LxW)", "size", 130, { cellEditor: "autoCompelete", hideForRoles: ['vendor'], roles: ['admin', 'sourcing_manager', 'sales', 'designer', 'production', 'vendor'] }),
        addColumn("Depth", "depth", 130, { cellEditor: "autoCompelete", hideForRoles: ['vendor'], roles: ['admin', 'sourcing_manager', 'sales', 'designer', 'production', 'vendor'] }),
        addColumn("Case Pack", "case_pack", 130, { roles: ['admin', 'sourcing_manager', 'sales', 'designer', 'production', 'vendor'] }),
        addColumn("Quantity", "quantity", 130, { roles: ['admin', 'sourcing_manager', 'sales', 'designer', 'production', 'vendor'] }),
        addColumn("Customer", "customer", 130, {cellEditor: "autoCompelete", roles: ['admin', 'sourcing_manager', 'sales', 'designer', 'production', 'vendor'] }),
        addColumn("License", "license", 150, {cellEditor: "autoCompelete", minWidth: 150, roles: ['admin', 'sourcing_manager', 'sales', 'designer', 'production'] }),
        addColumn("Delivery Location", "delivery_location", 180, {cellEditor: "autoCompelete", minWidth: 180, roles: ['admin', 'sourcing_manager', 'sales', 'designer', 'production'] }),
        addColumn("Comp Retail", "comp_retail", 130, { roles: ['admin', 'sourcing_manager', 'sales', 'designer'] }),
        addColumn("Assumed Wholesale", "assumed_wholesale", 130, { roles: ['admin', 'sourcing_manager', 'sales', 'designer'] }),
        addColumn("FOB Cost", "fob_cost", 130, { roles: ['admin', 'sourcing_manager', 'production'] }),
        addColumn("Duty Rate %", "duty_rate", 130, { roles: ['admin', 'sourcing_manager', 'production'] }),
        addColumn("Freight $", "freight", 130, { roles: ['admin', 'sourcing_manager', 'production'] }),
        addColumn("Landed Cost $", "landed_cost", 130, { roles: ['admin', 'sourcing_manager', 'production'] }),
        addColumn("Is Landed Cost Manual", "is_landed_cost_manual", 130, { hide: true, roles: ['admin', 'sourcing_manager', 'production'] }),
        addColumn("Container Price", "container_price", 130, {  cellEditor: "autoCompelete", roles: ['admin', 'sales'] }),
        addColumn("Dilution %", "dilution", 130, { roles: ['admin', 'sourcing_manager', 'sales', 'designer', 'production'] }),
        addColumn("Logistics Load %", "logistics_load", 130, { roles: ['admin'] }),
        addColumn("Gen FOB Sell Price", "gen_fob_sell_price", 130, { headerClass: "group-header-gen-fob", roles: ['admin'] }),
        addColumn("Gen FOB Margin %", "gen_fob_margin", 130, { headerClass: "group-header-gen-fob", roles: ['admin'] }),
        addColumn("Gen FOB Price for Sales", "gen_fob_price_sales", 130, { headerClass: "group-header-gen-fob", roles: ['admin', 'sales', 'designer'] }),
        addColumn("Gen POE Sell Price", "gen_poe_sell_price", 130, { headerClass: "group-header-gen-poe", roles: ['admin'] }),
        addColumn("Gen POE Margin %", "gen_poe_margin", 130, { headerClass: "group-header-gen-poe", roles: ['admin'] }),
        addColumn("Gen POE Price for Sales", "gen_poe_price_sales", 130, { headerClass: "group-header-gen-poe", roles: ['admin', 'sales', 'designer'] }),
        addColumn("Gen Whse Sell Price", "gen_whse_sell_price", 130, { headerClass: "group-header-gen-whse", roles: ['admin'] }),
        addColumn("Gen Whse Margin %", "gen_whse_margin", 130, { headerClass: "group-header-gen-whse", roles: ['admin'] }),
        addColumn("Gen Whse Price for Sales", "gen_whse_price_sales", 130, { headerClass: "group-header-gen-whse", roles: ['admin', 'sales', 'designer'] }),
        addColumn("Gen MDDP Sell Price", "gen_mddp_sell_price", 130, { headerClass: "group-header-gen-mddp", roles: ['admin'] }),
        addColumn("Gen MDDP Margin %", "gen_mddp_margin", 130, { headerClass: "group-header-gen-mddp", roles: ['admin'] }),
        addColumn("Gen MDDP Price for Sales", "gen_mddp_price_sales", 130, { headerClass: "group-header-gen-mddp", roles: ['admin', 'sales', 'designer'] }),
        addColumn("Lic MDDP Royalty %", "lic_mddp_royalty", 130, { headerClass: "group-header-lic-mddp", roles: ['admin'] }),
        addColumn("Lic MDDP Sell Price", "lic_mddp_sell_price", 130, { headerClass: "group-header-lic-mddp", roles: ['admin'] }),
        addColumn("Lic MDDP Margin %", "lic_mddp_margin", 130, { headerClass: "group-header-lic-mddp", roles: ['admin'] }),
        addColumn("Lic MDDP Price for Sales", "lic_mddp_price_sales", 130, { headerClass: "group-header-lic-mddp", roles: ['admin', 'sales', 'designer'] }),
        addColumn("Lic POE Royalty %", "lic_poe_royalty", 130, { headerClass: "group-header-lic-poe", roles: ['admin'] }),
        addColumn("Lic POE Margin %", "lic_poe_margin", 130, { headerClass: "group-header-lic-poe", roles: ['admin'] }),
        addColumn("Lic POE Sell Price", "lic_poe_sell_price", 130, { headerClass: "group-header-lic-poe", roles: ['admin'] }),
        addColumn("Lic POE Price for Sales", "lic_poe_price_sales", 130, { headerClass: "group-header-lic-poe", roles: ['admin', 'sales', 'designer'] }),
        addColumn("Lic FOB Royalty %", "lic_fob_royalty", 130, { headerClass: "group-header-lic-fob", roles: ['admin'] }),
        addColumn("Lic FOB Sell Price", "lic_fob_sell_price", 130, { headerClass: "group-header-lic-fob", roles: ['admin'] }),
        addColumn("Lic FOB Margin %", "lic_fob_margin", 130, { headerClass: "group-header-lic-fob", roles: ['admin'] }),
        addColumn("Lic FOB Price for Sales", "lic_fob_price_sales", 130, { headerClass: "group-header-lic-fob", roles: ['admin', 'sales', 'designer'] }),
        addColumn("Lic Whse Royalty %", "lic_whse_royalty", 130, { headerClass: "group-header-lic-whse", roles: ['admin'] }),
        addColumn("Lic Whse Sell Price", "lic_whse_sell_price", 130, { headerClass: "group-header-lic-whse", roles: ['admin'] }),
        addColumn("Lic Whse Margin %", "lic_whse_margin", 130, { headerClass: "group-header-lic-whse", roles: ['admin'] }),
        addColumn("Lic Whse Price for Sales", "lic_whse_price_sales", 130, { headerClass: "group-header-lic-whse", roles: ['admin', 'sales', 'designer'] }),
        addColumn("Notes", "note", 130, { roles: ['admin', 'sourcing_manager', 'sales', 'designer', 'production'] }),
        addColumn("Chosen Vendor", "chosen_vendor", 130, { roles: ['admin', 'sourcing_manager', 'production'] }),
        addColumn("Div", "div", 150, { hide: true, roles: ['admin', 'sourcing_manager', 'sales', 'designer', 'production'] }),
        addColumn("CBM/pc", "cbm_pc", 150, { roles: ['admin', 'sourcing_manager', 'production', 'vendor'] }),
        addColumn("Carton length", "carton_length", 200, {editable: false, roles: ['admin', 'sales'] }),
        addColumn("Carton width", "carton_width", 200, {hide: true, editable: false, roles: ['admin', 'sales'] }),
        addColumn("Carton height", "carton_height", 200, {hide: true, editable: false, roles: ['admin', 'sales'] }),
        addColumn("Res", "res", 130, { roles: ['admin', 'sourcing_manager', 'sales', 'designer', 'production'] }),
        addColumn("#Quote", "quote", 150, { roles: ['admin', 'sourcing_manager', 'production'] }),
        addColumn("Agent", "agent", 150, {hide: true, roles: ['admin'] }),
        addColumn("Status", "status", 120, {cellEditor: "autoCompelete", cellRenderer: "statusPillRenderer", minWidth: 120, roles: ['admin', 'sourcing_manager', 'sales', 'designer', 'production'] }),
        addColumn("adam_fix", "adam_fix", 130, {hide: true, roles: ['admin', 'sourcing_manager', 'sales', 'designer', 'production'] }),
    ];

    // Scenario pricing cells get a family tint cellClass (SPEC_V2 §5e). Gen =
    // blue family, Lic = violet family; the always-visible "Price for Sales"
    // leaf gets an extra emphasis class. Applied here (not per addColumn) so the
    // family rule stays in one place and any new scenario leaf picks it up. The
    // matching CSS lives in rfq.component.scss (.ag-cell.scenario-*).
    const SCENARIO_COL_RE = /^(gen|lic)_(fob|poe|whse|mddp)_/;
    return columns.map((col: any) => {
        const match = SCENARIO_COL_RE.exec(col.colId);
        if (!match) return col;
        const family = match[1]; // 'gen' | 'lic'
        const isPriceForSales = col.colId.endsWith("_price_sales");
        const cellClass = isPriceForSales
            ? `scenario-${family} scenario-${family}--sales`
            : `scenario-${family}`;
        return { ...col, cellClass };
    });
}

