@use "../../../styles" as styles;

:host {
  @include styles.page-component-layout;
}

/* ──────────────────────────────────────────────────────────────────────────
   RFQ grid reskin (SPEC_V2 §4 replacement block).
   The RFQ grid renders with the legacy `ag-theme-alpine` CSS theme, NOT the
   v35 Theming API, so the §4 colour/typography tokens are applied as Alpine
   CSS variables here instead of `themeQuartz.withParams`. All structural rules
   from SPEC_V2 §5 live below as ::ng-deep on real AG Grid classes.
   ────────────────────────────────────────────────────────────────────────── */
::ng-deep .ag-theme-alpine {
  // Accent + selection
  --ag-alpine-active-color: #D81B60;
  --ag-range-selection-background-color: rgba(216, 27, 96, 0.07);
  --ag-range-selection-border-color: #D81B60;
  --ag-checkbox-checked-color: #D81B60;

  // Backgrounds
  --ag-background-color: #ffffff;
  --ag-odd-row-background-color: #fbfcfd;
  --ag-row-hover-color: #fff5f8;
  --ag-selected-row-background-color: #fff5f8;
  --ag-header-background-color: #f7f9fc;

  // Text
  --ag-foreground-color: #475569;
  --ag-header-foreground-color: #475569;
  --ag-secondary-foreground-color: #7b8a9a;

  // Borders
  --ag-border-color: #e7e9ee;
  --ag-secondary-border-color: #eef1f5;
  --ag-row-border-color: #eef1f5;
  --ag-border-radius: 8px;

  // Typography
  --ag-font-size: 13px;
  --ag-font-family:
    "Hanken Grotesk", -apple-system, BlinkMacSystemFont, "Segoe UI", system-ui, sans-serif;
}

/* Re-quote / price-requested cell (SPEC_V2 §5h) */
::ng-deep .price-requested-cell {
  background-color: #fdeede !important;
  color: #e8833a !important;
}

/* --- Main Toolbar Layout --- */
.rfq-toolbar {
  display: flex;
  align-items: center;
  padding: 0px 16px;
  background-color: #fff;
  border-bottom: 1px solid #e0e0e0;
  height: auto;
  min-height: 55px; /* Sufficient height for inputs */
  box-sizing: border-box;
  flex-wrap: wrap; /* Allow wrapping on small screens */
  gap: 12px;
}

.toolbar-left, .toolbar-right {
  display: flex;
  align-items: center;
  gap: 12px;
}

.toolbar-spacer {
  flex: 1 1 auto;
}

.admin-group, .filter-group, .view-group, .utility-group {
  display: flex;
  align-items: center;
  gap: 8px;
}

/* --- Input & Field Styling --- */

.compact-field {
  width: 150px;
}

.wide-field {
  width: 180px;
}

/* Override Mat-Field to look like a box */
::ng-deep .mat-mdc-form-field-flex {
  align-items: center !important;
  background-color: #fff !important;
}

::ng-deep .mat-mdc-text-field-wrapper {
  background-color: #fff !important;
}

/* Center the select value text vertically within the form field */
::ng-deep .toolbar-field {
  .mat-mdc-form-field-infix {
    display: flex;
    align-items: center;
    min-height: 40px;
  }

  .mat-mdc-select {
    display: flex;
    align-items: center;
    margin-bottom: 3px;
  }

  .mat-mdc-select-value {
    display: flex;
    align-items: center;
    margin-bottom: 3px;
  }
}

/* --- Button Styling --- */

/* Primary Pink Button (SPEC_V2 §5i) */
.create-btn {
  background-color: #D81B60 !important; /* Brand Pink */
  color: #fff !important;
  border-radius: 8px !important; /* was 4px */
  height: 36px !important; /* was 40px (tighter) */
  padding: 0 20px;
  font-weight: 600 !important;
  box-shadow: 0 1px 2px rgba(216,27,96,0.3) !important;

  mat-icon {
    margin-right: 6px;
  }
}

/* Secondary Ghost/Outline Button (SPEC_V2 §5i) */
.secondary-btn {
  background-color: #fff !important;
  color: #475569 !important;
  border: 1px solid #e7e9ee !important; /* was #cfd8dc */
  height: 36px !important; /* was 40px */
  border-radius: 8px !important; /* was 4px */
  min-width: unset; /* Allows icon-only buttons to be square-ish */
  padding: 0 12px;

  mat-icon {
    color: #7b8a9a !important;
    font-size: 20px;
    width: 20px;
    height: 20px;
    margin: 0;
  }

  span {
    margin-left: 6px;
  }
}

/* Hairline dividers between toolbar groups (SPEC_V2 §5i) */
.toolbar-divider {
  width: 1px;
  height: 22px;
  background: #e7e9ee;
  align-self: center;
}

/* Density segmented toggle (SPEC_V2 §5i) */
.density-toggle {
  display: inline-flex;
  background: #eef1f5;
  border-radius: 8px;
  padding: 2px;
  gap: 2px;

  button {
    height: 28px;
    padding: 0 11px;
    border-radius: 6px;
    border: none;
    cursor: pointer;
    background: transparent;
    color: #7b8a9a;
    font-size: 12.5px;
    font-weight: 500;
    font-family: inherit;
    transition: background .1s, color .1s;

    &.active {
      background: #fff;
      color: #1a202e;
      font-weight: 600;
      box-shadow: 0 1px 2px rgba(0, 0, 0, 0.12);
    }
  }
}

/* --- View Dropdown Internals --- */
.view-dropdown-actions {
  padding: 8px;
  border-top: 1px solid #eee;
  display: flex;
  flex-direction: column;
  gap: 8px;
}

.view-btn-group {
  display: flex;
  justify-content: space-between;
}

.new-view-input {
  display: flex;
  gap: 8px;
  align-items: center;

  .view-input {
    border: 1px solid #ccc;
    padding: 6px;
    border-radius: 4px;
    width: 100%;
  }
}

/* --- Utilities --- */
.overlay-spinner {
  position: fixed;
  top: 0; left: 0;
  width: 100vw; height: 100vh;
  background: rgba(255, 255, 255, 0.7);
  display: flex;
  align-items: center;
  justify-content: center;
  z-index: 9999;
}

/* Responsive adjustments */
@media (max-width: 1000px) {
  .rfq-toolbar {
    height: auto;
    padding: 12px;
  }
  .toolbar-spacer {
    display: none; /* Stack items on small screens */
  }
  .toolbar-right {
    width: 100%;
    justify-content: space-between;
    flex-wrap: wrap;
  }
}

/* Row group rows / RFQ Group band (SPEC_V2 §5c) */
::ng-deep .grid-wrapper .ag-full-width-row,
::ng-deep .grid-wrapper .ag-row-group {
  background-color: #eef2f7 !important;
  border-bottom: 1px solid #d4dae3 !important;
}
::ng-deep .grid-wrapper .ag-row-group .ag-group-value,
::ng-deep .grid-wrapper .ag-row-group-leaf-indent {
  color: #1a202e !important;
  font-weight: 700 !important;
  font-size: 12px !important;
  letter-spacing: 0.01em;
}

::ng-deep .ag-paging-panel {
  justify-content: center !important;
}

::ng-deep .add-new-product-dialog .mat-mdc-dialog-container {
  height: auto !important;
  max-height: calc(100vh - 48px) !important;
  width: min(1350px, calc(100vw - 48px)) !important;
}

::ng-deep .add-new-product-dialog .mat-mdc-dialog-surface {
  max-height: calc(100vh - 48px) !important;
