/* Frozen identity pane seam (SPEC_V2 §5d). The last pinned-left header and cell
   get a rule + soft shadow so the pinned identity columns read as a pane.
   Default pinning of pic/desc and the firstDataRendered backfill are handled in
   later steps; this is the visual seam only. */
::ng-deep .grid-wrapper .ag-pinned-left-header .ag-header-cell:last-child,
::ng-deep .grid-wrapper .ag-header-cell.ag-cell-last-left-pinned {
  border-right: 1.5px solid #d4dae3 !important;
  box-shadow: 4px 0 8px -4px rgba(20, 30, 50, 0.18);
}
::ng-deep .grid-wrapper .ag-cell.ag-cell-last-left-pinned {
  border-right: 1.5px solid #d4dae3 !important;
  box-shadow: 4px 0 8px -4px rgba(20, 30, 50, 0.18);
}
/* Active-row highlight crosses the seam: let the row background show through
   pinned cells instead of each cell painting its own background. */
::ng-deep .grid-wrapper .ag-row-selected .ag-cell {
  background-color: transparent !important;
}

/* Scenario pricing cell tints (SPEC_V2 §5e). cellClass is set on the scenario
   leaf columns in rfq.grid.config.ts. Gen = blue family, Lic = violet family;
   the always-visible "Price for Sales" leaf is emphasised. */
::ng-deep .grid-wrapper .ag-cell.scenario-gen {
  background-color: #eaf1fd;
}
::ng-deep .grid-wrapper .ag-cell.scenario-lic {
  background-color: #f3ecfb;
}
::ng-deep .grid-wrapper .ag-cell.scenario-gen--sales {
  background-color: #e0ecfd !important;
  font-weight: 600;
  color: #1a202e !important;
  font-family: 'IBM Plex Mono', ui-monospace, Menlo, monospace;
  font-size: 12.5px;
  text-align: right;
}
::ng-deep .grid-wrapper .ag-cell.scenario-lic--sales {
  background-color: #ead9f7 !important;
  font-weight: 600;
  color: #1a202e !important;
  font-family: 'IBM Plex Mono', ui-monospace, Menlo, monospace;
  font-size: 12.5px;
  text-align: right;
}

::ng-deep .tech-pack-cell {
  display: flex;
  align-items: center;
  gap: 4px;
  min-width: 0;
  height: 100%;
}

::ng-deep .tech-pack-cell__text {
  flex: 1 1 auto;
  min-width: 0;
  overflow: hidden;
  text-overflow: ellipsis;
  white-space: nowrap;
  color: #1565c0;
}

::ng-deep .tech-pack-cell__button {
  flex: 0 0 auto;
  border: 1px solid #cfd8dc;
  border-radius: 4px;
  background: #fff;
  color: #37474f;
  cursor: pointer;
  font: inherit;
  font-size: 11px;
  line-height: 18px;
  padding: 0 5px;
}

::ng-deep .tech-pack-cell__button:disabled {
  color: #9e9e9e;
  cursor: default;
}

/* Custom status bar: remove the gray bar/line above the status bar (AG Grid top border) */
::ng-deep .grid-wrapper .ag-status-bar {
  border-top: 1px solid #e0e0e0 !important;
}

export const RFQ_DETAIL_COLUMN_HEADERS_CONFIG: any = {
    columnDefs: getColumnDefs()
};

function getColumnDefs() {
    const commonDefaults = {
        filter: false,
        cellRenderer: null,
        hide: false,
        rowDrag: false,
        rowGroup: false,
        headerName: null,
        editable: true,
        cellEditor: null,
        headerStyle: {}
    };

    const addColumn = (
        field: string,
        colId: string,
        width: number,
        overrides: any = {}
    ) => {
        const { roles, ...rest } = overrides;
        return {
            field,
            colId,
            width,
            ...commonDefaults,
            ...rest,
            ...(roles !== undefined ? { context: { roles } } : {})
        };
    };

    return [
        addColumn("Name", "name", 220, {
            pinned: "left",
            sortable: true,
            editable: true,
            roles: ['admin', 'sourcing_manager', 'sales', 'designer', 'production', 'vendor']
        }),
        addColumn("Price", "quote_price", 130, {
            sortable: true,
            roles: ['admin', 'sourcing_manager', 'sales', 'designer', 'production', 'vendor']
        }),
        addColumn("CBM/pc", "cbm_pc", 130, {
            sortable: true,
            roles: ['admin', 'sourcing_manager', 'sales', 'designer', 'production', 'vendor']
        }),
        addColumn("Note", "vendor_note", 320, {
            sortable: false,
            roles: ['admin', 'sourcing_manager', 'sales', 'designer', 'production', 'vendor']
        }),
        addColumn("Lead Time (days)", "lead_time", 130, {
            sortable: true,
            roles: ['admin', 'sourcing_manager', 'sales', 'designer', 'production', 'vendor']
        }),
        addColumn("Price Terms", "price_terms", 130, {
            sortable: true,
            cellEditor: "agSelectCellEditor",
            roles: ['admin', 'sourcing_manager', 'sales', 'designer', 'production', 'vendor']
        }),
        addColumn("FOB Country", "fob_country", 130, {
            sortable: true,
            cellEditor: "agSelectCellEditor",
            roles: ['admin', 'sourcing_manager', 'sales', 'designer', 'production', 'vendor']
        }),
        addColumn("FOB Port", "fob_port", 130, {
            sortable: true,
            roles: ['admin', 'sourcing_manager', 'sales', 'designer', 'production', 'vendor']
        }),
        addColumn("Quote Date", "quote_date", 140, {
            hide: true,
            filter: "agDateColumnFilter",
            sortable: true,
            roles: ['admin', 'sourcing_manager', 'sales', 'designer', 'production', 'vendor']
        }),
        addColumn("Submit", "submite_btn", 160, {
            hide: true,
            editable: false,
            roles: ['admin', 'sourcing_manager', 'sales', 'designer', 'production', 'vendor']
        })
    ];
}

