30	/**
31	 * Frontend sizing overrides for the backend-driven factory-quote detail grid
32	 * (SPEC_V2 §5k, hybrid model). The backend owns column identity/order; the
33	 * frontend only layers flex/minWidth/type/pinned onto specific columns by colId
34	 * so the row is gapless at any width — Note flexes to absorb the remainder, so
35	 * sizeColumnsToFit() must NOT be called (it fights flex). Keyed by both the live
36	 * colIds ('price', 'note') and the static-config variants ('quote_price',
37	 * 'vendor_note') so it works whichever the backend layout serves. All other
38	 * columns keep whatever the backend returned.
39	 */
40	export const DETAIL_COLUMN_SIZING: Record<string, Partial<ColDef>> = {
41	  name: { minWidth: 180, pinned: 'left' },
42	  price: { minWidth: 100, type: 'rightAligned' },
43	  quote_price: { minWidth: 100, type: 'rightAligned' },
44	  note: { flex: 1, minWidth: 200 },
45	  vendor_note: { flex: 1, minWidth: 200 },
46	};
