48	/** Merge the §5k sizing override (if any) onto a backend detail column def. */
49	export function applyDetailColumnSizing(col: any): any {
50	  if (!col || !col.colId) return col;
51	  const override = DETAIL_COLUMN_SIZING[col.colId];
52	  return override ? { ...col, ...override } : col;
53	}
