55	/**
56	 * Desired detail-grid column order (SPEC_V2 §5k):
57	 * Name · Price · Lead · CBM · Price Terms · FOB Country · FOB Port · Note.
58	 * Done in the frontend override step (no backend/DB change). Columns the backend
59	 * serves under a different colId are normalised via DETAIL_ORDER_ALIASES; any
60	 * column not listed sorts to the end, preserving the backend's relative order.
61	 */
62	export const DETAIL_COLUMN_ORDER: string[] = [
63	  'name', 'price', 'lead_time', 'cbm_pc', 'price_terms', 'fob_country', 'fob_port', 'note',
64	];
65	const DETAIL_ORDER_ALIASES: Record<string, string> = {
66	  quote_price: 'price',
67	  vendor_note: 'note',
68	};
69	
70	/** Reorder backend detail columns to DETAIL_COLUMN_ORDER (stable; unknowns last). */
71	export function orderDetailColumns(cols: any[]): any[] {
72	  if (!Array.isArray(cols)) return cols;
73	  const rank = (col: any): number => {
74	    const colId = col?.colId;
75	    const key = DETAIL_ORDER_ALIASES[colId] ?? colId;
76	    const i = DETAIL_COLUMN_ORDER.indexOf(key);
77	    return i === -1 ? Number.MAX_SAFE_INTEGER : i;
78	  };
79	  // Array.prototype.sort is stable, so unranked columns keep their backend order.
80	  return [...cols].sort((a, b) => rank(a) - rank(b));
81	}
