628	   * Filters columns based on user role
629	   * If a column has a 'roles' property, only show it if the user's role is included
630	   * If a column has no 'roles' property, it's visible to all users
631	   */
632	  private filterColumnsByRole(colHeaders: any[], role: string): any[] {
633	    // If no role is provided, return all columns
634	    if (!role) {
635	      return colHeaders;
636	    }
637	
638	    return colHeaders.filter((col: any) => {
639	      // If column has no roles property or empty roles array, it's visible to all
640	      if (!col.roles || !Array.isArray(col.roles) || col.roles.length === 0) {
