711	  private applyColumnEditablePolicy(column: any): any {
712	    const originalEditable = column?.editable;
713	    const disableForRoles = Array.isArray(column?.disableForRoles) ? column.disableForRoles : [];
714	    const allowEditOverride = !!column?.allowEditOverride;
715	    return {
716	      ...column,
717	      editable: (params: any) => {
718	        if (disableForRoles.includes(this.getNormalizedRole())) {
719	          if (!allowEditOverride || !this.canCurrentSalesUserEditDetailCells()) {
720	            return false;
721	          }
722	        }
723	        const baseEditable =
724	          typeof originalEditable === 'function'
725	            ? !!originalEditable(params)
726	            : originalEditable !== false;
727	        if (!baseEditable) {
728	          return false;
729	        }
730	        return this.canCurrentSalesUserEditDetailCells();
731	      },
732	    };
733	  }
