1329	  /** Parse a quote price into a finite number, defaulting to 0 when unparseable. */
1330	  private toPrice(value: any): number {
1331	    const numValue = typeof value === 'number' ? value : parseFloat(value);
1332	    return Number.isFinite(numValue) ? numValue : 0;
1333	  }
