1335	  /**
1336	   * A vendor quote row sorts to the bottom of the detail grid when it has no
1337	   * usable price (blank / zero / negative) or the factory declined to quote
1338	   * (req_status == 1). Used by the price default-sort comparator.
1339	   */
1340	  private isUnpricedOrDeclined(data: any): boolean {
1341	    if (!data) return true;
1342	    if (data.req_status == 1) return true;
1343	    const price = this.toPrice(data?.['Price']);
1344	    return price <= 0;
1345	  }
