1347	  /**
1348	   * Wires the detail grid's default sort: price ascending as the primary sort,
1349	   * with unpriced/declined rows pushed to the bottom. Mutates the matching
1350	   * colDef in place. The comparator reads the row's `Price` directly so it is
1351	   * independent of the column's colId/field/valueGetter.
1352	   */
1353	  private applyDefaultPriceSort(colHeaders: any[]): void {
1354	    if (!Array.isArray(colHeaders)) return;
1355	    const isPriceCol = (c: any) => c?.colId === 'quote_price' || c?.colId === 'price';
1356	    // Prefer a visible price column; fall back to any price column.
1357	    const priceCol =
1358	      colHeaders.find(c => isPriceCol(c) && c?.hide !== true) ||
1359	      colHeaders.find(c => isPriceCol(c));
1360	    if (!priceCol) return;
1361	
1362	    priceCol.sort = 'asc';
1363	    priceCol.sortIndex = 0;
1364	    priceCol.comparator = (_valueA: any, _valueB: any, nodeA: any, nodeB: any) => {
1365	      const aBottom = this.isUnpricedOrDeclined(nodeA?.data);
1366	      const bBottom = this.isUnpricedOrDeclined(nodeB?.data);
1367	      if (aBottom && bBottom) return 0;
1368	      if (aBottom) return 1;
1369	      if (bBottom) return -1;
1370	      return this.toPrice(nodeA?.data?.['Price']) - this.toPrice(nodeB?.data?.['Price']);
1371	    };
1372	  }
