1374	  private convertToNumberOrNull(value: any): number | null {
1375	    // Ensure the value is a number or null
1376	    if (value === null || value === undefined || value === '') {
1377	      return null;
1378	    }
1379	    const numValue = typeof value === 'number' ? value : parseFloat(value);
1380	    return isNaN(numValue) ? null : numValue;
1381	  }
