    this.allowAccessToSalesUsers = (this.configService.get('allowAccessToSalesUsers') as number[]) || [];
    this.enableSalesDetailEditing = !!this.configService.get('enableSalesDetailEditing');
    this.allowEditSalesUsersInDetailRenderer =
