density: 'compact' | 'standard' | 'comfortable' = 'standard';

readonly DENSITY_MAP = {
  compact:     { rowHeight: 30 },
  standard:    { rowHeight: 36 },
  comfortable: { rowHeight: 44 },
} as const;

setDensity(d: typeof this.density) {
  this.density = d;
