    new BehaviorSubject<{ key: string; theme: Theme }>(
      this.loadInitialTheme()
    );

  themeChange$ = this.themeChangeSubject.asObservable();

  private loadInitialTheme() {
    const savedKey = localStorage.getItem(this.STORAGE_KEY) || 'quartz';
    const theme = GRID_THEME_CONFIG[savedKey] ?? GRID_THEME_CONFIG.quartz;

    return { key: savedKey, theme };
  }

  emitThemeConfig(key: string, theme: Theme) {
    localStorage.setItem(this.STORAGE_KEY, key);
    this.themeChangeSubject.next({ key, theme });
  }

  getCurrentTheme() {
    return this.themeChangeSubject.value;
  }
}

