            [theme]="theme"
            <!-- other options -->
        />
    `,
})
export class AppComponent {
    // Custom Quartz theme that uses Material icons
    myTheme = themeQuartz
        .withParams({ /*...*/ })
        .withPart(iconSetMaterial);
}
```


