### Cell Style


Define rules to apply [Styling to Cells](ag-mcp://article/cell-styles) using `cellClassRules`. This can be used, for example, to set cell background colour based on its value.


```
.rag-green {
    background-color: #33cc3344;
}
```


```
<ag-grid-angular
    [columnDefs]="columnDefs"
    /* other grid options ... */ />

this.columnDefs = [{
    field: 'electric',
    cellClassRules: {
        // apply green to electric cars
        'rag-green': params => params.value === true,
    }
}];
```


### Row Style


Define rules to apply [Styling to Rows](ag-mcp://article/row-styles) using `rowClassRules`. This allows changing style (e.g. row colour) based on row values.


```
.rag-red {
    background-color: #cc222244;
}
```


```
<ag-grid-angular
    [rowClassRules]="rowClassRules"
    /* other grid options ... */ />

this.rowClassRules = {
    // apply red to Ford cars
    'rag-red': params => params.data.make === 'Ford',
};
```


