@if (toolbarVisible) {
  <mat-toolbar class="rfq-toolbar">
    <div class="toolbar-left">
      @if (role !='vendor') {
        <button
          mat-flat-button
          color="accent"
          class="create-btn"
          (click)="onNewProduct()">
          <mat-icon>add</mat-icon>
          <span>Add Product</span>
        </button>
      }
      @if (role == 'admin') {
        <div class="admin-group">
          @if (ReminderSelectVisiblity) {
            <button
              mat-stroked-button
              class="secondary-btn"
              (click)="onReminder()">
              <mat-icon>notifications</mat-icon>
              <span>Reminder</span>
            </button>
          }
          @if (multiSelectVisiblity) {
            <button
              mat-stroked-button
              class="secondary-btn"
              (click)="onMultipleQuote()">
              <mat-icon>format_list_bulleted</mat-icon>
              <span>Multi Quote</span>
            </button>
          }
        </div>
      }
      @if (role != 'vendor' && addFactoriesSelectVisibility) {
        <button
          mat-stroked-button
          class="secondary-btn"
          (click)="onBulkAddFactories()">
          <mat-icon>domain_add</mat-icon>
          <span>Add Factories</span>
        </button>
      }
      @if (role === 'vendor') {
        <button
          mat-flat-button
          color="accent"
          class="create-btn"
          (click)="onFactoryBulkUpload()"
          matTooltip="Download a pre-filled template, complete it, then upload your offers in bulk. / 下载预填模板，填写后批量上传报价。">
          <mat-icon>upload_file</mat-icon>
          <span>Upload Offers</span>
        </button>
      }
    </div>
    <span class="toolbar-spacer"></span>
    <div class="toolbar-right">
      <div class="filter-group">
        @if (role !='vendor') {
          <mat-form-field appearance="outline" class="toolbar-field compact-field" subscriptSizing="dynamic">
            <mat-label>Division</mat-label>
            <mat-select [(value)]="selectedDivisionCode" (selectionChange)="onDivisionCodeChange($event)" multiple>
              @for (data of divisionCode; track data) {
                <mat-option [value]="data">
                  {{data.division_name}}
                </mat-option>
              }
            </mat-select>
          </mat-form-field>
        }
        @if (role !='vendor') {
          <mat-form-field appearance="outline" class="toolbar-field compact-field" subscriptSizing="dynamic">
            <mat-label>Status</mat-label>
            <mat-select [(value)]="selectedDivisionCodeStatus" (selectionChange)="onDivisionCStatusChange($event)" multiple>
              @for (data of divisionCodeStatus; track data) {
                <mat-option [value]="data">
                  {{data.RFQItemStatus_title}}
                </mat-option>
              }
            </mat-select>
          </mat-form-field>
        }
      </div>
      <div class="toolbar-divider"></div>
      @if (access != 'temporary') {
        <div class="view-group">
          <layout-dropdown [gridApi]="gridApi" gridId="rfq" [selectedView]="selectedViewLayout"></layout-dropdown>
          <mat-form-field appearance="outline" class="toolbar-field wide-field" (click)="newViewInput = false" subscriptSizing="dynamic">
            <mat-label>View</mat-label>
            <mat-select #select [(value)]="selectedViewLayout" [compareWith]="compareViewLayouts" (selectionChange)="onViewChange($event.value)">
              @for (viewLayout of viewLayouts; track viewLayout.layout_name) {
                <mat-option [value]="viewLayout">
                  {{ viewLayout.layout_name }}@if (viewLayout.is_default) { (default) }
                </mat-option>
              }
              <div class="view-dropdown-actions" (click)="$event.stopPropagation()">
                @if (newViewInput) {
                  <div class="new-view-input">
                    <input #newView class="view-input" placeholder="View Name" />
                    <button mat-stroked-button color="primary" (click)="onSaveNewView(newView.value);newViewInput = false">Save</button>
                  </div>
                }
                @if (!newViewInput) {
                  <div class="view-btn-group">
                    <button mat-button color="primary" (click)="onSaveLayout(selectedViewLayout)">Save Current</button>
                    <button mat-button color="primary" (click)="newViewInput = true">Add New</button>
                    @if (selectedViewLayout?.layout_name !== 'Default' && !selectedViewLayout?.is_default) {
                      <button mat-button color="primary" (click)="onSetRfqViewAsDefault()">
                        Set as default
                      </button>
                    }
                    <button
                      mat-button
                      color="primary"
                      (click)="onClearRfqDefaultView()"
                      [disabled]="!hasRfqDefaultView()"
                      [matTooltip]="!hasRfqDefaultView() ? 'No default view is set. Select a view and click Set as default first. / 还没有设置默认视图。请先选择一个视图并点击 Set as default。' : ''">
                      Clear default
                    </button>
                  </div>
                }
              </div>
            </mat-select>
          </mat-form-field>
        </div>
      }
      <div class="density-toggle" role="group" aria-label="Row density">
        <button type="button" [class.active]="density === 'compact'" (click)="setDensity('compact')">Compact</button>
        <button type="button" [class.active]="density === 'standard'" (click)="setDensity('standard')">Standard</button>
        <button type="button" [class.active]="density === 'comfortable'" (click)="setDensity('comfortable')">Comfortable</button>
      </div>
      <div class="toolbar-divider"></div>
      <div class="utility-group">
        <button mat-stroked-button class="secondary-btn" (click)="onBtExport()" [disabled]="isExporting" matTooltip="Export">
          <mat-icon>file_download</mat-icon>
        </button>
        <button mat-stroked-button class="secondary-btn" (click)="onToggleAll()" matTooltip="Expand/Collapse">
          <mat-icon>unfold_more</mat-icon>
        </button>
        <button mat-stroked-button id="undoBtn" class="secondary-btn" (click)="undo()" matTooltip="Undo">
          <mat-icon>undo</mat-icon>
        </button>
      </div>
    </div>
  </mat-toolbar>
}

