import {
    themeQuartz,
    themeBalham,
    themeMaterial,
    themeAlpine,
    Theme,
    colorSchemeLightWarm,
    colorSchemeLightCold,
    colorSchemeDarkWarm,
    colorSchemeDarkBlue,
  } from 'ag-grid-enterprise';

  // ────────────────────────────────────────────────────────────────────────────
  // RFQ brand theme (SPEC_V2 §4). The RFQ grid is on the v35 Theming API, so all
  // colour / typography tokens live here in themeQuartz.withParams() — NOT as
  // `--ag-*` CSS variables or `.ag-theme-alpine` overrides (those do nothing once
  // a Theme object is bound via [theme], see SPEC_V2 §2). Structural rules
  // (heights, seam, cell-class tints) stay as ::ng-deep in rfq.component.scss.
  // Param names validated against the v35 Theming API (themeQuartz.withParams).
  // ────────────────────────────────────────────────────────────────────────────
  const themePink: Theme = themeQuartz.withParams({
    // ── Accent + selection ──────────────────────────────────────────────────
    accentColor: '#D81B60',
    rangeSelectionBackgroundColor: 'rgba(216,27,96,0.07)',
    rangeSelectionBorderColor: '#D81B60',

    // ── Background + row colours ────────────────────────────────────────────
    backgroundColor: '#ffffff',
    oddRowBackgroundColor: '#fbfcfd',
    rowHoverColor: '#fff5f8',
    selectedRowBackgroundColor: '#fff5f8',

    // ── Foreground / text ───────────────────────────────────────────────────
    foregroundColor: '#1a202e',
    textColor: '#475569',
    cellTextColor: '#475569',

    // ── Borders ─────────────────────────────────────────────────────────────
    borderColor: '#e7e9ee',
    wrapperBorder: { color: '#e7e9ee', width: 1 },
    wrapperBorderRadius: 8,
    borderRadius: 0,
    rowBorder: { color: '#eef1f5', width: 1 },
    columnBorder: { color: '#e7e9ee', width: 1 },
    headerColumnBorder: { color: '#e7e9ee', width: 1 },

    // ── Header ──────────────────────────────────────────────────────────────
    headerBackgroundColor: '#f7f9fc',
    headerTextColor: '#475569',
    headerFontWeight: 600,
    headerFontSize: 11,

    // ── Typography ──────────────────────────────────────────────────────────
    fontFamily:
      '"Hanken Grotesk", -apple-system, BlinkMacSystemFont, "Segoe UI", system-ui, sans-serif',
    fontSize: 13,

    // ── Spacing ─────────────────────────────────────────────────────────────
    spacing: 8,
    cellHorizontalPadding: 10,
    rowVerticalPaddingScale: 1,
  });

  // Detail (factory-quote) sub-grid theme (SPEC_V2 §5k). Same brand theme as the
  // master grid; the card surround (#eef3f9 / pink rule) is applied via the
  // detail renderer's component SCSS, so the grid rows stay white for legibility.
  const themePinkDetail: Theme = themePink;

  export { themePink, themePinkDetail };

  // Export all themes in one place
  export const GRID_THEME_CONFIG: Record<string, Theme> = {
    // Default themes
    quartz: themeQuartz,
    balham: themeBalham,
    material: themeMaterial,
    alpine: themeAlpine,

    // Custom
    custom: themePink,

    // Color schemes
    quartzLightWarm: themeQuartz.withPart(colorSchemeLightWarm),
    quartzLightCold: themeQuartz.withPart(colorSchemeLightCold),
    quartzDarkWarm: themeQuartz.withPart(colorSchemeDarkWarm),
    quartzDarkBlue: themeQuartz.withPart(colorSchemeDarkBlue),
  };

