import { themeQuartz } from 'ag-grid-enterprise';
import { GRID_THEME_CONFIG, themePink, themePinkDetail } from './grid-themes.config';

/**
 * Guards the RFQ brand theme wiring (SPEC_V2 §4). The RFQ grid renders its
 * colour/typography reskin only because a Theme object is bound via [theme];
 * if themePink were ever dropped or reverted to a bare CSS-variable approach the
 * reskin would silently stop rendering (SPEC_V2 §2). These tests lock in that
 * the theme is a real, customised Theming-API object and stays wired into the
 * shared theme map.
 */
describe('grid-themes.config (RFQ Theming API)', () => {
  it('exports themePink as a Theming API theme object', () => {
    expect(themePink).toBeDefined();
    expect(typeof themePink).toBe('object');
  });

  it('customises the base Quartz theme (not the unmodified default)', () => {
    // withParams() returns a new theme instance distinct from the base theme.
    expect(themePink).not.toBe(themeQuartz);
  });

  it('exposes a detail sub-grid theme (SPEC_V2 §5k)', () => {
    expect(themePinkDetail).toBeDefined();
    expect(typeof themePinkDetail).toBe('object');
  });

  it('registers themePink as the "custom" theme in GRID_THEME_CONFIG', () => {
    expect(GRID_THEME_CONFIG.custom).toBe(themePink);
  });

  it('keeps the built-in themes available alongside the custom theme', () => {
    expect(GRID_THEME_CONFIG.quartz).toBe(themeQuartz);
    expect(GRID_THEME_CONFIG.alpine).toBeDefined();
    expect(GRID_THEME_CONFIG.balham).toBeDefined();
    expect(GRID_THEME_CONFIG.material).toBeDefined();
  });
});

