(() => {
  const out = {};
  const wrapper = document.querySelector('.ag-root-wrapper');
  out.gridFound = !!wrapper;
  if (wrapper) {
    out.wrapperClasses = wrapper.className;
    const cs = getComputedStyle(wrapper);
    out.wrapperBg = cs.backgroundColor;
    out.wrapperFont = cs.fontFamily;
  }
  const cell = document.querySelector('.ag-cell');
  if (cell) {
    const cs = getComputedStyle(cell);
    out.cellBg = cs.backgroundColor;
    out.cellColor = cs.color;
    out.cellFont = cs.fontFamily;
  }
  const header = document.querySelector('.ag-header');
  if (header) out.headerBg = getComputedStyle(header).backgroundColor;
  // theme-related elements
  out.themeAlpineEls = document.querySelectorAll('[class*="ag-theme-alpine"]').length;
  out.agGridAngularClass = document.querySelector('ag-grid-angular')?.className || null;
  // injected theme style tags
  out.agThemeStyleTags = Array.from(document.querySelectorAll('style')).filter(s => /--ag-|ag-theme|\.ag-root/.test(s.textContent||'')).length;
  // Look for any element with a generated ag theme class (Theming API adds e.g. ag-theme-{hash} or sets data attrs)
  out.bodyDataAgThemeMode = document.body.dataset.agThemeMode || null;
  // Hanken loaded?
  out.hankenLoaded = !!Array.from(document.fonts).find(f => /Hanken/i.test(f.family));
  return out;
})()

(() => {
  const out = {};
  out.url = location.href;
  out.splashVisible = !!document.querySelector('#vex-splash-screen');
  const wrapper = document.querySelector('.ag-root-wrapper');
  out.gridFound = !!wrapper;
  const agng = document.querySelector('ag-grid-angular');
