    out.wrapperParentClass = wrapper.closest('[class*="ag-theme"]')?.className || null;
  }
  const cell = document.querySelector('.ag-row .ag-cell');
  if (cell) {
    const cs = getComputedStyle(cell);
    out.cellBg = cs.backgroundColor; out.cellColor = cs.color; out.cellFont = cs.fontFamily.slice(0,40);
  }
  const hdr = document.querySelector('.ag-header');
  if (hdr) out.headerBg = getComputedStyle(hdr).backgroundColor;
  out.alpineEls = document.querySelectorAll('[class*="ag-theme-alpine"]').length;
  // does the doc have the legacy ag-theme-alpine stylesheet loaded?
  out.hasAlpineCssRule = (() => { try {
    for (const ss of document.styleSheets) { try { const t = (ss.ownerNode && ss.ownerNode.textContent) || ''; if (/\.ag-theme-alpine\b/.test(t)) return true; } catch(e){} }
    return 'unknown-or-cross-origin';
  } catch(e){ return 'err'; }})();
  return out;
})()

(() => {
  const out = {};
  const wrap = document.querySelector('.ag-root-wrapper');
  const wcs = getComputedStyle(wrap);
  // Theming API sets these CSS vars on the theme element
  out.varFont = wcs.getPropertyValue('--ag-font-family').trim().slice(0,60);
  out.varFg = wcs.getPropertyValue('--ag-foreground-color').trim();
  out.varBg = wcs.getPropertyValue('--ag-background-color').trim();
  out.varHeaderBg = wcs.getPropertyValue('--ag-header-background-color').trim();
  out.varAccent = wcs.getPropertyValue('--ag-accent-color').trim();
  out.varRowHover = wcs.getPropertyValue('--ag-row-hover-color').trim();
  // sample several normal cells (skip selected). pick a cell in row 3
  const rows = document.querySelectorAll('.ag-center-cols-container .ag-row');
  out.rowCount = rows.length;
  const sampleCell = rows[2]?.querySelector('.ag-cell') || document.querySelector('.ag-cell');
  if (sampleCell) {
    const cs = getComputedStyle(sampleCell);
    out.sampleCellBg = cs.backgroundColor;
    out.sampleCellColor = cs.color;
    out.sampleCellFont = cs.fontFamily.slice(0,50);
  }
  // What is body / app font?
  out.bodyFont = getComputedStyle(document.body).fontFamily.slice(0,50);
  // Is there a global rule forcing font on .ag-cell? check a few stylesheets for ".ag-cell" font-family
  const hits = [];
  for (const ss of document.styleSheets) {
    let rules; try { rules = ss.cssRules; } catch(e){ continue; }
    if (!rules) continue;
    for (const r of rules) {
      const sel = r.selectorText;
      if (sel && /\.ag-(cell|row|theme)/.test(sel) && r.style && (r.style.fontFamily || r.style.color)) {
        hits.push({sel: sel.slice(0,80), font: r.style.fontFamily.slice(0,30), color: r.style.color, imp: r.style.getPropertyPriority('font-family')});
        if (hits.length >= 12) break;
      }
    }
    if (hits.length >= 12) break;
  }
  out.cssHitsForCellFontColor = hits;
  return out;
})()

