(async () => {
  const out = {};
  const res = performance.getEntriesByType('resource')
    .map(r => r.name)
    .filter(n => /\.js(\?|$)/.test(n) && n.includes('alsand2.designflow.app'));
  out.totalJs = res.length;
  let hanken=false, ibm=false, pinkThemeFont=false, checked=0, rfqChunk=null;
  const hits=[];
  for (const url of res) {
    try {
      const txt = await fetch(url).then(r=>r.text());
      checked++;
      if (/Hanken Grotesk/.test(txt)) { hanken=true; hits.push('HANKEN:'+url.split('/').pop()); }
      if (/IBM Plex Sans/.test(txt)) { ibm=true; hits.push('IBM:'+url.split('/').pop()); }
      // the exact themePink fontFamily string fragment
      if (/Hanken Grotesk", -apple-system/.test(txt)) pinkThemeFont=true;
      if (/rfq[._-]?grid|rfqTheme|themePink/i.test(txt)) rfqChunk = (rfqChunk||'') + url.split('/').pop()+' ';
    } catch(e) {}
  }
  out.checked = checked;
  out.foundHankenGrotesk = hanken;
  out.foundIBMPlexSans = ibm;
  out.hits = hits.slice(0,10);
  out.rfqRelatedChunks = rfqChunk;
  return out;
})()

(() => {
  const out = {};
  const api = window.gridApi;
  out.hasApi = !!api;
  if (api && api.getGridOption) {
    const theme = api.getGridOption('theme');
    out.themeType = typeof theme;
    out.themeIsString = (typeof theme === 'string') ? theme : null;
    if (theme && typeof theme === 'object') {
      // Theme objects carry their params; try to surface them
      try { out.themeKeys = Object.keys(theme).slice(0,20); } catch(e){}
      // The params may be on a private field; stringify a shallow probe
      try {
        const s = JSON.stringify(theme, (k,v)=> typeof v==='function' ? '[fn]' : v);
        out.themeJsonSnippet = s ? s.slice(0, 600) : null;
      } catch(e){ out.themeJsonErr = String(e); }
      // look for our markers anywhere in the object graph
      const probe = JSON.stringify(theme, (k,v)=> typeof v==='function'?undefined:v) || '';
      out.themeMentionsPink = /D81B60/i.test(probe);
      out.themeMentionsHanken = /Hanken/i.test(probe);
    }
  }
  return out;
})()

(async () => {
  const out = {};
  const html = await fetch('https://alsand2.designflow.app/index.html?ts=' + Date.now(), {cache:'no-store'}).then(r=>r.text());
  out.indexHasHankenLink = /Hanken\+Grotesk/.test(html);
  out.indexHasPlexMono = /IBM\+Plex\+Mono/.test(html);
  // which main bundle does the fresh index reference?
  const m = html.match(/main-[A-Z0-9]+\.js/i);
  out.indexMainBundle = m ? m[0] : null;
  out.currentMainBundle = Array.from(document.scripts).map(s=>s.src.split('/').pop()).find(n=>/^main-/.test(n));
  // also: is there a <ag-grid-angular ... theme  binding in the live rfq chunk? check the alpine class removal
  out.indexLen = html.length;
  return out;
})()

