  const pink = base.withParams({ accentColor:'#D81B60', rowHoverColor:'#fff5f8', selectedRowBackgroundColor:'#fff5f8', headerBackgroundColor:'#f7f9fc', backgroundColor:'#ffffff' });
  api.setGridOption('theme', pink);
  const accentImmediately = getComputedStyle(document.querySelector('.ag-root-wrapper')).getPropertyValue('--ag-accent-color').trim();
  await new Promise(r=>setTimeout(r, 2500));
  const accentAfter = getComputedStyle(document.querySelector('.ag-root-wrapper')).getPropertyValue('--ag-accent-color').trim();
  const boundAfter = JSON.stringify(api.getGridOption('theme'), (k,v)=>typeof v==='function'?undefined:v)||'';
  return { accentImmediately, accentAfter, stillPinkAfter: /D81B60/i.test(boundAfter) };
})()

