input.text:
(async () => {
  const out = {};
  // service worker?
  out.hasServiceWorker = 'serviceWorker' in navigator;
  if (out.hasServiceWorker) {
    const regs = await navigator.serviceWorker.getRegistrations();
    out.swCount = regs.length;
    out.swScopes = regs.map(r=>r.scope);
  }
  // loaded rfq chunks + does any contain the re-assert sequence (setGridOption theme right before rowHeight density)?
  const res = performance.getEntriesByType('resource').map(r=>r.name).filter(n=>/\.js(\?|$)/.test(n) && /alsand2/.test(n));
  let reassertFound=false, rfqChunks=[];
  for (const url of res) {
    try {
      const txt = await fetch(url).then(r=>r.text());
      if (/rfqTheme|rfq\.component|onGridReady/i.test(txt)) rfqChunks.push(url.split('/').pop());
      // re-assert: a setGridOption("theme", x.rfqTheme) — look for rfqTheme used as a property near setGridOption("theme"
      if (/setGridOption\("theme",[^)]*rfqTheme/.test(txt) || /"theme",\s*this\.rfqTheme/.test(txt)) reassertFound=true;
      // looser: the property assignment rfqTheme = ... themePink
      if (/rfqTheme=/.test(txt) && /setGridOption\("theme"/.test(txt)) reassertFound = reassertFound || 'maybe';
    } catch(e){}
  }
  out.rfqChunks = rfqChunks.slice(0,6);
  out.reassertFound = reassertFound;
  return out;
})()
